def _batched(iterable: cabc.Iterable[V], batch_size: int) -> cabc.Iterator[tuple[V, ...]]:
    """Group ``iterable`` into tuples of up to ``batch_size`` items each.
    Unlike :func:`batch`, the final group is yielded even if it has fewer
    than ``batch_size`` items.
    """
    it = iter(iterable)

    while chunk := tuple(islice(it, batch_size)):
        yield chunk"}

